// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // Weather condition to emoji mapping
  const getWeatherEmoji = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    if (conditionLower.includes('hail')) return '🧊';
    return '🌤️'; // Default fallback
  };

  // Forecast items with safe defaults
  const forecastItems = props.forecast && props.forecast.length > 0 ? props.forecast : [];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* City and Current Temperature */}
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Row gap="var(--ggui-spacing-3)" align="center" justify="center">
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">{props.temperature}°{props.unit}</Text>
                <Text size="3xl" color="var(--ggui-color-onSurfaceVariant)" aria-label={`${props.condition}`}>{getWeatherEmoji(props.condition)}</Text>
              </Row>
              <Text size="lg" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
            </Stack>

            <Divider margin="var(--ggui-spacing-3)" color="var(--ggui-color-outlineVariant)" />

            {/* Humidity and Wind Speed */}
            <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Row gap="var(--ggui-spacing-1)" align="center" justify="center">
                  <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                  <Text size="xl" color="var(--ggui-color-onSurfaceVariant)" aria-label="Water droplet, representing humidity">💧</Text>
                </Row>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Row gap="var(--ggui-spacing-1)" align="center" justify="center">
                  <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} m/s</Text>
                  <Text size="xl" color="var(--ggui-color-onSurfaceVariant)" aria-label="Wind, representing wind speed">💨</Text>
                </Row>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast Strip */}
        {forecastItems.length > 0 && (
          <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="lg">
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
              <Row gap="var(--ggui-spacing-3)" wrap>
                {forecastItems.map((dayForecast, index) => (
                  <Box
                    key={index}
                    padding="var(--ggui-spacing-3)"
                    background="var(--ggui-color-surfaceVariant)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    style={{ flex: '1 1 100px', minWidth: '100px' }}
                    role="region"
                    aria-label={`${dayForecast.day || `Day ${index + 1}`} forecast`}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)" align="center">
                        {dayForecast.day || `Day ${index + 1}`}
                      </Text>
                      <Text size="2xl" color="var(--ggui-color-onSurfaceVariant)" align="center" aria-label={`Weather condition: ${dayForecast.icon ? dayForecast.icon : 'Clear'}`}>
                        {dayForecast.icon ? dayForecast.icon : getWeatherEmoji('Clear')}
                      </Text>
                      <Row gap="var(--ggui-spacing-1)" justify="center">
                        <Text size="sm" weight="semibold" color="var(--ggui-color-onSurface)">{dayForecast.high || '--'}°</Text>
                        <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">{dayForecast.low || '--'}°</Text>
                      </Row>
                    </Stack>
                    </Box>
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

