// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [newTaskColumn, setNewTaskColumn] = useState<string>(props.columns[0]?.id || 'todo');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [showAddForm, setShowAddForm] = useState<string | null>(null);

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'delete' && task?.id) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      } else if (task?.id) {
        setTasks((prev) => {
          const idx = prev.findIndex((t) => t.id === task.id);
          if (idx >= 0) {
            const updated = [...prev];
            updated[idx] = { ...updated[idx], ...task };
            return updated;
          }
          return action === 'create' ? [...prev, task] : prev;
        });
      }
    }
  }, [taskChanged.latest]);

  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    const updatedTasks = tasks.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t));
    setTasks(updatedTasks);
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [tasks, taskUpdate]);

  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    const updatedTasks = tasks.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t));
    setTasks(updatedTasks);
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo', title: newTitle } });
    setEditingId(null);
  }, [tasks, taskUpdate]);

  const handleAddTask = useCallback((columnId: string, title: string, priority: 'low' | 'medium' | 'high') => {
    if (!title.trim()) return;
    const newTask = { id: `task-${Date.now()}`, title, priority, column: columnId };
    setTasks((prev) => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setShowAddForm(null);
  }, [taskUpdate]);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  const priorityColor = (priority: 'low' | 'medium' | 'high' | undefined) => {
    switch (priority) {
      case 'high': return 'var(--ggui-color-error-500)';
      case 'medium': return 'var(--ggui-color-warning-500)';
      default: return 'var(--ggui-color-success-500)';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Text variant="body" weight="semibold">
              {completedTasks} of {totalTasks} tasks completed
            </Text>
            <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} variant="success" size="sm" />
          </Row>
        </Card>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns.map((column) => {
            const columnTasks = tasks.filter((t) => t.column === column.id);
            return (
              <Card key={column.id} padding="var(--ggui-spacing-4)" shadow="sm" style={{ flex: '0 0 300px', minHeight: '600px' }}>
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column Header */}
                  <Box>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                      {column.name} ({columnTasks.length})
                    </Text>
                  </Box>
                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Task Cards */}
                  <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                    {columnTasks.map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="sm" radius="md" as={Clickable} onClick={() => {}} hoverStyle={{ opacity: 0.9 }}>
                        <Stack gap="var(--ggui-spacing-2)">
                          {/* Task Title */}
                          {editingId === task.id ? (
                            <Stack gap="var(--ggui-spacing-2)" align="stretch">
                              <Input
                                label=""
                                value={editingTitle}
                                onChange={setEditingTitle}
                                placeholder="Task title"
                                size="sm"
                              />
                              <Row gap="var(--ggui-spacing-2)" justify="end">
                                <Button variant="ghost" size="sm" onClick={() => setEditingId(null)}>Cancel</Button>
                                <Button variant="primary" size="sm" onClick={() => handleEditTask(task.id!, editingTitle)}>Save</Button>
                              </Row>
                            </Stack>
                          ) : (
                            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                              <Text
                                variant="body"
                                weight="medium"
                                as={Clickable}
                                onClick={() => { setEditingId(task.id!); setEditingTitle(task.title || ''); }}
                                style={{ cursor: 'pointer' }}
                              >
                                {task.title}
                              </Text>
                              <Button
                                variant="ghost"
                                size="sm"
                                leftIcon={<Icon name="edit-2" size={16} />}
                                onClick={() => { setEditingId(task.id!); setEditingTitle(task.title || ''); }}
                              />
                            </Row>
                          )}

                          {/* Priority Badge */}
                          {task.priority && (
                            <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'} size="sm">
                              {task.priority}
                            </Badge>
                          )}

                          {/* Assignee & Due Date */}
                          <Row gap="var(--ggui-spacing-2)" align="center">
                            {task.assignee && <Avatar name={task.assignee} size="sm" />}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {task.dueDate}
                              </Text>
                            )}
                          </Row>

                          {/* Move Button / Dropdown */}
                          {editingId !== task.id && (
                            <Dropdown
                              trigger={<Button variant="outline" size="sm">Move</Button>}
                              options={props.columns
                                .filter((c) => c.id !== column.id)
                                .map((c) => ({ value: c.id!, label: c.name! }))
                              }
                              value=""
                              onChange={(newColId) => handleMoveTask(task.id!, newColId)}
                            />
                          )}
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Add Task Button */}
                  {showAddForm === column.id ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md" background="var(--ggui-color-primary-50)">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="between">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => { setShowAddForm(null); setNewTaskTitle(''); }}
                          >
                            Cancel
                          </Button>
                          <Button
                            variant="primary"
                            size="sm"
                            onClick={() => handleAddTask(column.id!, newTaskTitle, newTaskPriority)}
                          >
                            Add
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="ghost"
                      size="sm"
                      fullWidth
                      onClick={() => setShowAddForm(column.id!)}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

