// Category color map using design tokens
const CATEGORY_COLORS: Record<string, { bg: string; text: string }> = {
  'alkali metal': { bg: 'var(--ggui-color-primary-100)', text: 'var(--ggui-color-primary-900)' },
  'alkaline earth metal': { bg: 'var(--ggui-color-success-100)', text: 'var(--ggui-color-success-900)' },
