  'actinide': { bg: 'var(--ggui-color-error-100)', text: 'var(--ggui-color-error-900)' },
  'nonmetal': { bg: 'var(--ggui-color-primary-50)', text: 'var(--ggui-color-primary-700)' },
  'halogen': { bg: 'var(--ggui-color-warning-50)', text: 'var(--ggui-color-warning-700)' },
  'noble-gas': { bg: 'var(--ggui-color-info-50)', text: 'var(--ggui-color-info-700)' },
  'metalloid': { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)' },
}; // Add 'var(--ggui-color-surfaceVariant)' as fallback

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

export default function Component(props: Props) {
  // State for search and selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        (el.name?.toLowerCase().includes(query) || false) ||
        (el.symbol?.toLowerCase().includes(query) || false)
    );
  }, [searchQuery, props.elements]);

  // Get unique categories and their colors for legend
  const uniqueCategories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach((el) => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Element cell component
  const ElementCell = ({ element }: { element: ElementData }) => {
    const colors = CATEGORY_COLORS[element.category || ''] || {
      bg: 'var(--ggui-color-surfaceVariant)',
      text: 'var(--ggui-color-onSurfaceVariant)',
    };
    const gridRow = element.row || 1;
    const gridCol = element.col || 1;
    return (
      <Card
        as={Clickable}
        onClick={() => setSelectedElement(element)}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            setSelectedElement(element);
          }
        }}
        padding="var(--ggui-spacing-3)"
        shadow="sm"
        radius="md"
        border={false}
        aria-label={`${element.name}, atomic number ${element.atomicNumber}`}
        tabIndex={0}
        style={{
          gridRow,
          gridColumn: gridCol,
          background: colors.bg,
          cursor: 'pointer',
          transition: 'all 200ms ease-in-out',
          minHeight: '80px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
        }}
      >
        {element.atomicNumber && (
          <Text
            variant="caption"
            color={colors.text}
            style={{
              position: 'absolute',
              top: 'var(--ggui-spacing-2)',
              left: 'var(--ggui-spacing-2)',
              fontSize: 'var(--ggui-font-size-xs)',
            }}
          >
            {element.atomicNumber}
          </Text>
        )}
        {element.symbol && (
          <Text
            variant="label"
            color={colors.text}
            align="center"
            weight="bold"
            style={{
              fontSize: '20px',
            }}
          >
            {element.symbol}
          </Text>
        )}
      </Card>
    );
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant)" variant="body">
            Interactive periodic table with {props.elements.length} elements
          </Text>
        </Stack>

        {/* Search Input */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          onSearch={() => {}}
          placeholder="Search by element name or symbol..."
          size="md"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurface)" weight="semibold">
              Legend
            </Text>
            <Row gap="var(--ggui-spacing-2)" wrap>
              {uniqueCategories.map((category) => {
                const colors = CATEGORY_COLORS[category] || {
                  bg: 'var(--ggui-color-surfaceVariant)',
                  text: 'var(--ggui-color-onSurfaceVariant)',
                };
                return (
                  <Stack key={category} direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                    <Box
                      background={colors.bg}
                      borderRadius="var(--ggui-shape-radius-sm)"
                      style={{ width: '24px', height: '24px' }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurface)">{category}</Text>
                  </Stack>
                );
              })}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <div
          role="region"
          aria-label="Periodic table grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(80px, 1fr))',
            gridAutoRows: '80px',
            gap: 'var(--ggui-spacing-2)',
            padding: 'var(--ggui-spacing-4)',
            background: 'var(--ggui-color-surface)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
            border: '1px solid var(--ggui-color-outlineVariant)',
            overflowX: 'auto',
            minHeight: '500px',
          }}
        >
          {filteredElements.length > 0 ? (
            filteredElements.map((element) => (
              <ElementCell key={element.symbol || element.atomicNumber} element={element} />
            ))
          ) : (
            <div
              style={{
                gridColumn: '1 / -1',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                color: 'var(--ggui-color-onSurfaceVariant)',
              }}
            >
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No elements found matching "{searchQuery}"
              </Text>
            </div>
          )}
        </div>

        {/* Selected Element Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)" shadow="md">
            <Stack gap="var(--ggui-spacing-3)">
              <Row justify="between" align="center">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Row>
              <Divider margin="var(--ggui-spacing-2)" />
              <Row gap="var(--ggui-spacing-6)" wrap>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Number
                  </Text>
                  <Text variant="bodyLarge" weight="semibold">
                    {selectedElement.atomicNumber}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Symbol
                  </Text>
                  <Text variant="bodyLarge" weight="semibold">
                    {selectedElement.symbol}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Weight
                  </Text>
                  <Text variant="bodyLarge" weight="semibold">
                    {selectedElement.atomicWeight?.toFixed(2) || 'N/A'}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Category
                  </Text>
                  <Badge
                    variant="primary"
                    pill
                    size="md"
                  >
                    {selectedElement.category || 'Unknown'}
                  </Badge>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

