// Star rating display component
function StarRating({ rating }: { rating?: number }) {
  const stars = Array.from({ length: 5 }, (_, i) => i < (rating || 0));
  return (
    <Row gap="var(--ggui-spacing-1)" align="center">
      {stars.map((filled, i) => (
        <Icon
          key={i}
          name="star"
          size={16}
          color={filled ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
        />
      ))}
    </Row>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Handlers
  const handleQuantityChange = useCallback((value: number) => {
    const stock = props.product.stock || 0;
    const newQuantity = Math.max(1, Math.min(value, stock));
    setQuantity(newQuantity);
  }, [props.product.stock]);

  const handleDecrement = useCallback(() => {
    setQuantity(prev => Math.max(1, prev - 1));
  }, []);

  const handleIncrement = useCallback(() => {
    const stock = props.product.stock || 0;
    setQuantity(prev => Math.min(stock, prev + 1));
  }, [props.product.stock]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Computed values
  const isOutOfStock = (props.product.stock || 0) <= 0;
  const isLowStock = (props.product.stock || 0) > 0 && (props.product.stock || 0) < 5;
  const stockStatus = isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock';
  const stockVariant = isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success';

