  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (!inputText.trim()) return;
    sendMessage({ text: inputText, timestamp: new Date().toISOString() });
    setInputText('');
  }, [inputText, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Determine active typing indicator
  const isTyping = typing.latest?.active && typing.latest?.sender !== props.currentUser;
  const typingSender = typing.latest?.sender;

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    for (const msg of allMessages) {
      if (groups.length > 0 && groups[groups.length - 1].sender === msg.sender) {
        groups[groups.length - 1].messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg] });
      }
    }
    return groups;
  }, [allMessages]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-0)" center>
      <Stack direction="vertical" gap="0" align="stretch" style={{ height: '100vh', display: 'flex' }}>
