              </Stack>
            )}
          </Row>
        </Card>

        <Divider orientation="horizontal" margin="0" />

        {/* Messages Area */}
        <Stack direction="vertical" gap="var(--ggui-spacing-3)" align="stretch" style={{ flex: 1, overflow: 'auto', padding: 'var(--ggui-spacing-4)' }}>
          {groupedMessages.map((group, groupIndex) => {
            const isOwnMessage = group.sender === props.currentUser;
            return (
              <Stack
                key={groupIndex}
                as="article"
                direction="vertical"
                gap="var(--ggui-spacing-2)"
                align={isOwnMessage ? 'end' : 'start'}
                aria-label={`Message from ${group.sender || 'Unknown'}`}
              >
                {group.sender && !isOwnMessage && (
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ paddingLeft: 'var(--ggui-spacing-3)' }}>
                    {group.sender}
                  </Text>
                )}
                <Stack
                  direction="vertical"
                  gap="var(--ggui-spacing-1)"
                  align={isOwnMessage ? 'end' : 'start'}
                >
                  {group.messages.map((msg, msgIndex) => (
                    <Box
                      key={msgIndex}
                      padding="var(--ggui-spacing-3)"
                      background={isOwnMessage ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                      borderRadius="var(--ggui-shape-radius-lg)"
                      style={{ maxWidth: '70%', wordWrap: 'break-word' }}
                    >
                      <Text
                        variant="body"
                        color={isOwnMessage ? 'white' : 'var(--ggui-color-onSurface)'}
                      >
                        {msg.text}
                      </Text>
                      {msg.timestamp && (
                        <Text
                          variant="caption"
                          color={isOwnMessage ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                          style={{ marginTop: 'var(--ggui-spacing-1)' }}
                        >
                          {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </Text>
                      )}
                    </Box>
                  ))}
                </Stack>
              </Stack>
            );
          })}
          <div ref={messagesEndRef} />
        </Stack>

        <Divider orientation="horizontal" margin="0" />

        {/* Input Area */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)">
