            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Preferences</Heading>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={handleRoleChange}
                options={roleSelectOptions}
                placeholder="Select your role"
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={handleNotificationsToggle}
              />

              {/* Theme Preference Toggle */}
              <Toggle
                label="Dark Theme"
                checked={formData.theme === 'dark'}
                onChange={handleThemeToggle}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3 - Review & Confirm */}
        {step === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" width="100%" maxWidth="500px">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Setup</Heading>

              {/* Summary */}
              <Box paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                  <Text variant="body" weight="semibold">{formData.name}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                  <Text variant="body" weight="semibold">{formData.email}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                  <Text size="lg">{formData.avatar}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                  <Text variant="body" weight="semibold">{formData.role}</Text>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text>
                  <Badge variant={formData.emailNotifications ? 'success' : 'default'}>
                    {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                  </Badge>
                </Row>
                <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

                <Row justify="between">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                  <Text variant="body" weight="semibold">{formData.theme === 'dark' ? 'Dark' : 'Light'}</Text>
                </Row>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="center">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={step === 1}
          >
            Back
          </Button>

          {step < 3 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canProceedFromStep}
            >
              Next
            </Button>
          )}

          {step === 3 && (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
